// src/checkout/tax.ts
export type TaxInput={subtotal:number;state:string;exempt:boolean};
export const calcTax=(i:TaxInput):number=>{
  if(i.exempt)return 0;
  const rates:Record<string,number>={AK:0,DE:0,MT:0,NH:0,OR:0,CA:0.0725,NY:0.04,TX:0.0625,HI:0.04};
  const r=rates[i.state];
  if(r===undefined)throw new Error(`Unknown state ${i.state}`);
  return Math.round(i.subtotal*r*100)/100;
};

