const CASES:Array<[string,number,number]>=[['AK',10000,0],['CA',10000,725],['NY',10000,400],['HI',10000,400],['DE',10000,0]];
describe('calcTax',()=>{
  it.each(CASES)('state=%s subtotal=%i → tax=%i cents',(state,sub,expected)=>{
    expect(Math.round(calcTax({subtotal:sub/100,state,exempt:false})*100)).toBe(expected);
  });
  it('honors exemption regardless of state',()=>{
    expect(calcTax({subtotal:1000,state:'CA',exempt:true})).toBe(0);
  });
  it('throws on unknown state — fail loud, never silently zero',()=>{
    expect(()=>calcTax({subtotal:100,state:'ZZ',exempt:false})).toThrow();
  });
});

// tests/matchers/money.ts
import {expect} from 'vitest';
export type Money={amount:bigint;currency:string;scale:number};
const fmt=(m:Money):string=>`${(Number(m.amount)/10**m.scale).toFixed(m.scale)} ${m.currency}`;
expect.extend({
  toEqualMoney(received:Money,expected:Money){
    if(received.currency!==expected.currency){
      return {pass:false,message:()=>`Currency mismatch: expected ${expected.currency}, got ${received.currency}. Refusing to compare amounts across currencies.`};
    }
    if(received.scale!==expected.scale){
      return {pass:false,message:()=>`Scale mismatch for ${received.currency}: expected ${expected.scale}, got ${received.scale}`};
    }
    const pass=received.amount===expected.amount;
    return {pass,message:()=>pass?`Expected NOT ${fmt(expected)}`:`Expected ${fmt(expected)}, got ${fmt(received)} (diff: ${received.amount-expected.amount})`};
  }
});
declare module 'vitest'{interface Assertion<T>{toEqualMoney(expected:Money):T}}

