// tests/setup/db.ts
import {Pool} from 'pg';
import {readFileSync,readdirSync} from 'node:fs';
import {join} from 'node:path';
export const pool=new Pool({connectionString:process.env.TEST_DATABASE_URL});
export async function migrate(){
  const files=readdirSync('migrations').filter(f=>f.endsWith('.sql')).sort();
  for(const f of files)await pool.query(readFileSync(join('migrations',f),'utf8'));
}
export async function withTx<T>(fn:(client:import('pg').PoolClient)=>Promise<T>):Promise<void>{
  const client=await pool.connect();
  try{
    await client.query('BEGIN');
    await fn(client);
  }finally{
    await client.query('ROLLBACK');
    client.release();
  }
}

