describe('POST /orders',()=>{
  it('creates order + items atomically and decrements inventory',async()=>{
    await withTx(async(c)=>{
      await c.query("INSERT INTO products(sku,inventory) VALUES('A',10),('B',5)");
      const res=await request(app).post('/orders').send({items:[{sku:'A',qty:2},{sku:'B',qty:1}]}).expect(201);
      const order=await c.query('SELECT id FROM orders WHERE id=$1',[res.body.id]);
      const items=await c.query('SELECT sku,qty FROM order_items WHERE order_id=$1 ORDER BY sku',[res.body.id]);
      const inv=await c.query("SELECT sku,inventory FROM products ORDER BY sku");
      expect(order.rowCount).toBe(1);
      expect(items.rows).toEqual([{sku:'A',qty:2},{sku:'B',qty:1}]);
      expect(inv.rows).toEqual([{sku:'A',inventory:8},{sku:'B',inventory:4}]);
    });
  });
  it('rolls back entire order when one SKU is out of stock',async()=>{
    await withTx(async(c)=>{
      await c.query("INSERT INTO products(sku,inventory) VALUES('A',10),('B',0)");
      await request(app).post('/orders').send({items:[{sku:'A',qty:1},{sku:'B',qty:1}]}).expect(409);
      const items=await c.query('SELECT COUNT(*)::int n FROM order_items');
      const inv=await c.query("SELECT inventory FROM products WHERE sku='A'");
      expect(items.rows[0].n).toBe(0); // no orphan rows
      expect(inv.rows[0].inventory).toBe(10); // not debited
    });
  });
});

// src/billing/prorate.ts
export type ProrateInput={newPriceCents:number;creditCents:number;daysLeft:number;cycleDays:number};
export const prorate=(i:ProrateInput):number=>{
  if(i.cycleDays<=0)throw new Error('cycleDays must be positive');
  if(i.daysLeft<0||i.daysLeft>i.cycleDays)throw new Error('daysLeft out of range');
  const raw=Math.round(i.newPriceCents*(i.daysLeft/i.cycleDays));
  return Math.max(0,raw-i.creditCents);
};

// src/billing/prorate.property.test.ts
import {describe,it} from 'vitest';
import fc from 'fast-check';
import {prorate} from './prorate';

const input=fc.record({
  newPriceCents:fc.integer({min:0,max:1_000_000_00}),
  creditCents:fc.integer({min:0,max:1_000_000_00}),
  cycleDays:fc.integer({min:1,max:366}),
  daysLeft:fc.integer({min:0,max:366})
}).filter(i=>i.daysLeft<=i.cycleDays);

describe('prorate properties',()=>{
  it('never returns negative',()=>{
    fc.assert(fc.property(input,(i)=>prorate(i)>=0),{numRuns:1000});
  });
  it('never exceeds new price minus credit',()=>{
    fc.assert(fc.property(input,(i)=>prorate(i)<=Math.max(0,i.newPriceCents-i.creditCents)),{numRuns:1000});
  });
  it('returns 0 on the last day of the cycle (daysLeft=0)',()=>{
    fc.assert(fc.property(input.map(i=>({...i,daysLeft:0})),(i)=>prorate(i)===0),{numRuns:200});
  });
  it('returns full price minus credit on day 1 (daysLeft=cycleDays)',()=>{
    fc.assert(fc.property(input.map(i=>({...i,daysLeft:i.cycleDays})),(i)=>{
      const expected=Math.max(0,i.newPriceCents-i.creditCents);
      return prorate(i)===expected;
    }),{numRuns:200});
  });
  it('is monotonic in daysLeft (more days = more proration, never less)',()=>{
    fc.assert(fc.property(input,fc.integer({min:0,max:30}),(i,delta)=>{
      const extra=Math.min(i.daysLeft+delta,i.cycleDays);
      return prorate({...i,daysLeft:extra})>=prorate(i);
    }),{numRuns:500});
  });
});

