// tests/factories/user.factory.ts
import {faker} from '@faker-js/faker';
import {UserSchema,type User} from '../../src/domain/user';
export type UserTrait='admin'|'enterprise'|'newSignup';
export function userFactory(overrides:Partial<User>={},trait?:UserTrait):User{
  const base:User={
    id:faker.string.uuid(),
    email:faker.internet.email(),
    subscriptionTier:'free',
    createdAt:faker.date.past({years:1}),
    isAdmin:false
  };
  const withTrait:User=trait==='admin'?{...base,isAdmin:true,subscriptionTier:'enterprise'}
    :trait==='enterprise'?{...base,subscriptionTier:'enterprise'}
    :trait==='newSignup'?{...base,createdAt:new Date()}:base;
  const result={...withTrait,...overrides};
  return UserSchema.parse(result); // throws if factory ever produces invalid data
}

