// src/clock.ts
export interface Clock{now():number}
export const SystemClock:Clock={now:()=>Date.now()};
export class FakeClock implements Clock{
  constructor(private t:number){}
  now=()=>this.t;
  advance=(ms:number)=>{this.t+=ms;};
  set=(t:number)=>{this.t=t;};
}

