// src/hooks/useDebounced.ts
import {useEffect,useState} from 'react';
export function useDebounced<T>(value:T,ms:number):T{
  const [debounced,setDebounced]=useState(value);
  useEffect(()=>{
    const t=setTimeout(()=>setDebounced(value),ms);
    return ()=>clearTimeout(t);
  },[value,ms]);
  return debounced;
}

// src/hooks/useDebounced.test.tsx
import {describe,it,expect,beforeEach,afterEach,vi} from 'vitest';
import {renderHook,act} from '@testing-library/react';
import {useDebounced} from './useDebounced';

beforeEach(()=>{vi.useFakeTimers();});
afterEach(()=>{vi.useRealTimers();});

describe('useDebounced',()=>{
  it('returns initial value synchronously',()=>{
    const {result}=renderHook(({v})=>useDebounced(v,200),{initialProps:{v:'a'}});
    expect(result.current).toBe('a');
  });
  it('suppresses rapid changes within the window',()=>{
    const {result,rerender}=renderHook(({v})=>useDebounced(v,200),{initialProps:{v:'a'}});
    rerender({v:'b'});
    rerender({v:'c'});
    act(()=>{vi.advanceTimersByTime(199);});
    expect(result.current).toBe('a');
    act(()=>{vi.advanceTimersByTime(1);});
    expect(result.current).toBe('c');
  });
  it('restarts the timer when ms changes mid-flight (REGRESSION GUARD)',()=>{
    const {result,rerender}=renderHook(({v,m}:{v:string;m:number})=>useDebounced(v,m),{initialProps:{v:'a',m:200}});
    rerender({v:'b',m:200});
    act(()=>{vi.advanceTimersByTime(150);});
    rerender({v:'b',m:500}); // ms changes mid-flight
    act(()=>{vi.advanceTimersByTime(200);}); // would fire under old 200ms timer
    expect(result.current).toBe('a'); // still old value — new ms restarted the wait
    act(()=>{vi.advanceTimersByTime(300);});
    expect(result.current).toBe('b');
  });
  it('does not fire after unmount',()=>{
    const {result,rerender,unmount}=renderHook(({v})=>useDebounced(v,200),{initialProps:{v:'a'}});
    rerender({v:'b'});
    unmount();
    act(()=>{vi.advanceTimersByTime(500);});
    expect(result.current).toBe('a'); // last value before unmount, no late update
  });
});

