import {Pool} from 'pg';
import {readdirSync,readFileSync} from 'node:fs';
import {join} from 'node:path';

const workerId=process.env.VITEST_POOL_ID??'main';
export const SCHEMA=`test_w${workerId}`;
export const pool=new Pool({connectionString:process.env.TEST_DATABASE_URL,max:5});

pool.on('connect',(client)=>{client.query(`SET search_path TO "${SCHEMA}",public`);});

export async function setupSchema():Promise<void>{
  const admin=await pool.connect();
  try{
    await admin.query(`DROP SCHEMA IF EXISTS "${SCHEMA}" CASCADE`);
    await admin.query(`CREATE SCHEMA "${SCHEMA}"`);
    await admin.query(`SET search_path TO "${SCHEMA}",public`);
    const migrations=readdirSync('migrations').filter(f=>f.endsWith('.sql')).sort();
    for(const f of migrations){
      await admin.query(readFileSync(join('migrations',f),'utf8'));
    }
  }finally{admin.release();}
}

export async function teardownSchema():Promise<void>{
  const admin=await pool.connect();
  try{await admin.query(`DROP SCHEMA "${SCHEMA}" CASCADE`);}finally{admin.release();}
  await pool.end();
}

