// src/cart/cart.ts
export type Item={sku:string;qty:number;priceCents:number};
export class Cart{
  private items=new Map<string,Item>();
  add(sku:string,qty:number,priceCents:number):void{
    const existing=this.items.get(sku);
    if(existing)existing.qty+=qty;
    else this.items.set(sku,{sku,qty,priceCents});
  }
  remove(sku:string):void{this.items.delete(sku);}
  updateQty(sku:string,qty:number):void{
    if(qty<=0){this.remove(sku);return;}
    const i=this.items.get(sku);
    if(i)i.qty=qty;
  }
  clear():void{this.items.clear();}
  get totalCents():number{return [...this.items.values()].reduce((s,i)=>s+i.qty*i.priceCents,0);}
  get lines():ReadonlyArray<Item>{return [...this.items.values()];}
}

// src/cart/cart.model.test.ts
import {describe,it} from 'vitest';
import fc from 'fast-check';
import {Cart} from './cart';

type Cmd={type:'add';sku:string;qty:number;price:number}|{type:'remove';sku:string}|{type:'updateQty';sku:string;qty:number}|{type:'clear'};
const skuArb=fc.constantFrom('A','B','C','D');
const cmdArb=fc.oneof(
  fc.record({type:fc.constant('add' as const),sku:skuArb,qty:fc.integer({min:1,max:5}),price:fc.integer({min:1,max:10000})}),
  fc.record({type:fc.constant('remove' as const),sku:skuArb}),
  fc.record({type:fc.constant('updateQty' as const),sku:skuArb,qty:fc.integer({min:0,max:10})}),
  fc.record({type:fc.constant('clear' as const)})
);

function runModel(cmds:Cmd[]):{total:number;lines:number}{
  const model=new Map<string,{qty:number;price:number}>();
  for(const c of cmds){
    if(c.type==='add'){const e=model.get(c.sku);if(e){e.qty+=c.qty;e.price=c.price;}else model.set(c.sku,{qty:c.qty,price:c.price});}
    else if(c.type==='remove')model.delete(c.sku);
    else if(c.type==='updateQty'){if(c.qty<=0)model.delete(c.sku);else{const e=model.get(c.sku);if(e)e.qty=c.qty;}}
    else if(c.type==='clear')model.clear();
  }
  return {total:[...model.values()].reduce((s,v)=>s+v.qty*v.price,0),lines:model.size};
}
function runReal(cmds:Cmd[]):{total:number;lines:number}{
  const cart=new Cart();
  for(const c of cmds){
    if(c.type==='add')cart.add(c.sku,c.qty,c.price);
    else if(c.type==='remove')cart.remove(c.sku);
    else if(c.type==='updateQty')cart.updateQty(c.sku,c.qty);
    else if(c.type==='clear')cart.clear();
  }
  return {total:cart.totalCents,lines:cart.lines.length};
}

describe('Cart invariants vs reference model',()=>{
  it('real implementation agrees with model on totals and line count',()=>{
    fc.assert(fc.property(fc.array(cmdArb,{minLength:0,maxLength:30}),(cmds)=>{
      const m=runModel(cmds);
      const r=runReal(cmds);
      return m.total===r.total&&m.lines===r.lines;
    }),{numRuns:500,seed:42});
  });
  it('quantity never negative',()=>{
    fc.assert(fc.property(fc.array(cmdArb,{maxLength:30}),(cmds)=>{
      const cart=new Cart();
      for(const c of cmds){
        if(c.type==='add')cart.add(c.sku,c.qty,c.price);
        else if(c.type==='remove')cart.remove(c.sku);
        else if(c.type==='updateQty')cart.updateQty(c.sku,c.qty);
        else cart.clear();
      }
      return cart.lines.every(l=>l.qty>=1);
    }),{numRuns:500});
  });
});

