// src/middleware/rate-limit.ts
import type {RequestHandler} from 'express';
import type {Clock} from '../clock';
export interface RateStore{incr(key:string,windowMs:number,now:number):Promise<number>}

export function createInMemoryStore():RateStore{
  const data=new Map<string,{count:number;resetAt:number}>();
  return {
    async incr(key,windowMs,now){
      const e=data.get(key);
      if(!e||now>=e.resetAt){data.set(key,{count:1,resetAt:now+windowMs});return 1;}
      e.count++;return e.count;
    }
  };
}

export function rateLimit(opts:{max:number;windowMs:number;store:RateStore;clock:Clock;keyFn?:(req:any)=>string}):RequestHandler{
  return async(req,res,next)=>{
    const key=opts.keyFn?opts.keyFn(req):req.ip??'unknown';
    const count=await opts.store.incr(key,opts.windowMs,opts.clock.now());
    res.setHeader('X-RateLimit-Limit',opts.max);
    res.setHeader('X-RateLimit-Remaining',Math.max(0,opts.max-count));
    if(count>opts.max){res.status(429).json({error:'rate_limited'});return;}
    next();
  };
}

