import request from 'supertest';
import {rateLimit,createInMemoryStore} from './rate-limit';
import {FakeClock} from '../clock';

function buildApp(clock:FakeClock){
  const app=express();
  app.use(rateLimit({max:5,windowMs:60_000,store:createInMemoryStore(),clock,keyFn:(req)=>req.headers['x-test-ip'] as string}));
  app.get('/',(_,res)=>res.json({ok:true}));
  return app;
}

describe('rateLimit middleware',()=>{
  it('allows up to 5, blocks the 6th',async()=>{
    const clock=new FakeClock(0);
    const app=buildApp(clock);
    for(let i=0;i<5;i++){
      const r=await request(app).get('/').set('x-test-ip','1.1.1.1');
      expect(r.status).toBe(200);
    }
    const blocked=await request(app).get('/').set('x-test-ip','1.1.1.1');
    expect(blocked.status).toBe(429);
