// src/ui/ErrorBoundary.tsx
import React from 'react';
interface Props{fallback:(args:{error:Error;reset:()=>void})=>React.ReactNode;onError?:(e:Error)=>void;resetKeys?:ReadonlyArray<unknown>;children:React.ReactNode}
interface State{error:Error|null}
export class ErrorBoundary extends React.Component<Props,State>{
  state:State={error:null};
  static getDerivedStateFromError(error:Error):State{return {error};}
  componentDidCatch(error:Error){this.props.onError?.(error);}
  componentDidUpdate(prev:Props){
    if(this.state.error&&prev.resetKeys&&this.props.resetKeys&&prev.resetKeys.some((k,i)=>k!==this.props.resetKeys![i])){
      this.setState({error:null});
    }
  }
  reset=()=>this.setState({error:null});
  render(){
    if(this.state.error)return this.props.fallback({error:this.state.error,reset:this.reset});
    return this.props.children;
  }
}

