// scripts/balance-shards.ts — run weekly to rebalance assignments
import {readFileSync,writeFileSync} from 'node:fs';
const report=JSON.parse(readFileSync('playwright-report/data.json','utf8')) as {suites:Array<{file:string;duration:number}>};
const SHARDS=6;
const files=report.suites.map(s=>({file:s.file,duration:s.duration})).sort((a,b)=>b.duration-a.duration);
const shards:Array<{files:string[];total:number}>=Array.from({length:SHARDS},()=>({files:[],total:0}));
for(const f of files){
  const target=shards.reduce((min,s,i,arr)=>s.total<arr[min].total?i:min,0);
  shards[target].files.push(f.file);
  shards[target].total+=f.duration;
}
writefileSync('.playwright-shards.json',JSON.stringify(shards,null,2));
console.log('Shard balance:',shards.map(s=>`${s.files.length}f/${(s.total/1000).toFixed(1)}s`));

