// src/auth/AuthContext.tsx
import React,{createContext,useContext,useState,useMemo,useCallback} from 'react';
export type User={id:string;name:string;email:string};
const AuthStateContext=createContext<User|null>(null);
const AuthDispatchContext=createContext<{login:(u:User)=>void;logout:()=>void}|null>(null);

export function AuthProvider({children}:{children:React.ReactNode}){
  const [user,setUser]=useState<User|null>(null);
  const dispatch=useMemo(()=>({
    login:(u:User)=>setUser(u),
    logout:()=>setUser(null)
  }),[]); // stable forever
  return (
    <AuthDispatchContext.Provider value={dispatch}>
      <AuthStateContext.Provider value={user}>{children}</AuthStateContext.Provider>
    </AuthDispatchContext.Provider>
  );
}
export const useAuthUser=()=>useContext(AuthStateContext);
export const useAuthActions=()=>{
  const d=useContext(AuthDispatchContext);
  if(!d)throw new Error('useAuthActions outside provider');
  return d;
};

