import {describe,it,expect,vi} from 'vitest';
import {render,screen} from '@testing-library/react';
import {userEvent} from '@testing-library/user-event';
import {memo,useRef} from 'react';
import {AuthProvider,useAuthUser,useAuthActions} from './AuthContext';

function makeCounter(){
  const counts={a:0,b:0};
  const A=memo(function A(){counts.a++;useAuthActions();return <div>A</div>;});
  const B=memo(function B(){counts.b++;const u=useAuthUser();return <div>B:{u?.name??'none'}</div>;});
  return {A,B,counts};
}

describe('AuthContext re-render granularity',()=>{
  it('dispatch-only consumer does NOT re-render on state change',async()=>{
    const {A,B,counts}=makeCounter();
    function Login(){
      const {login}=useAuthActions();
      return <button onClick={()=>login({id:'1',name:'Ada',email:'a@b.co'})}>login</button>;
    }
    render(<AuthProvider><A/><B/><Login/></AuthProvider>);
    expect(counts).toEqual({a:1,b:1});
    await userEvent.setup().click(screen.getByRole('button',{name:/login/i}));
    expect(counts.a).toBe(1); // A subscribes to dispatch only — should not re-render
    expect(counts.b).toBe(2); // B subscribes to user — re-renders correctly
    expect(screen.getByText('B:Ada')).toBeInTheDocument();
  });
  it('dispatch reference is stable across re-renders',()=>{
    const seen=new Set<unknown>();
    function Probe(){const a=useAuthActions();seen.add(a);return null;}
    const {rerender}=render(<AuthProvider><Probe/></AuthProvider>);
    rerender(<AuthProvider><Probe/></AuthProvider>);
    expect(seen.size).toBe(1); // same dispatch object → memoized children skip
  });
});

