// src/webhooks/stripe.ts
import type {Request,Response,RequestHandler} from 'express';
import crypto from 'node:crypto';
import type {Clock} from '../clock';

const TOLERANCE_SEC=300;
function verify(payload:Buffer,signatureHeader:string,secret:string,now:number):boolean{
  const parts=Object.fromEntries(signatureHeader.split(',').map(p=>p.split('=')));
  const ts=Number(parts.t);
  const sig=parts.v1;
  if(!ts||!sig)return false;
  if(Math.abs(now-ts)>TOLERANCE_SEC)return false;
  const signed=`${ts}.${payload.toString('utf8')}`;
  const expected=crypto.createHmac('sha256',secret).update(signed).digest('hex');
  try{return crypto.timingSafeEqual(Buffer.from(sig,'hex'),Buffer.from(expected,'hex'));}
  catch{return false;}
}

export function createStripeWebhook(opts:{secret:string;clock:Clock;processEvent:(e:any)=>Promise<void>}):RequestHandler{
  const processed=new Set<string>();
  return async(req:Request,res:Response)=>{
    const sig=req.header('stripe-signature');
    if(!sig)return res.status(400).send('missing signature');
    const body=req.body as Buffer; // express.raw applied at route level
    if(!verify(body,sig,opts.secret,Math.floor(opts.clock.now()/1000))){
      return res.status(401).send('invalid signature');
    }
    const event=JSON.parse(body.toString('utf8'));
    if(processed.has(event.id))return res.status(200).json({duplicate:true});
    await opts.processEvent(event);
    processed.add(event.id);
    res.status(200).json({received:true});
  };
}

// src/webhooks/stripe.test.ts
import {describe,it,expect,vi} from 'vitest';
import express from 'express';
import request from 'supertest';
import crypto from 'node:crypto';
import {createStripeWebhook} from './stripe';
import {FakeClock} from '../clock';

const SECRET='whsec_test_secret';
function sign(payload:string,ts:number,secret=SECRET){
  const signed=`${ts}.${payload}`;
  const v1=crypto.createHmac('sha256',secret).update(signed).digest('hex');
  return `t=${ts},v1=${v1}`;
}
function buildApp(clock:FakeClock,processEvent=vi.fn().mockResolvedValue(undefined)){
  const app=express();
  app.post('/webhooks/stripe',express.raw({type:'application/json'}),createStripeWebhook({secret:SECRET,clock,processEvent}));
  return {app,processEvent};
}

describe('Stripe webhook',()=>{
  it('accepts a valid signature within tolerance',async()=>{
    const clock=new FakeClock(1_700_000_000_000);
    const {app,processEvent}=buildApp(clock);
    const body=JSON.stringify({id:'evt_1',type:'charge.succeeded'});
    const sig=sign(body,1_700_000_000);
    await request(app).post('/webhooks/stripe').set('stripe-signature',sig).set('content-type','application/json').send(Buffer.from(body)).expect(200);
    expect(processEvent).toHaveBeenCalledOnce();
  });
  it('REJECTS forged signature with 401',async()=>{
    const clock=new FakeClock(1_700_000_000_000);
    const {app,processEvent}=buildApp(clock);
    const body=JSON.stringify({id:'evt_2',type:'charge.succeeded',amount:0});
    await request(app).post('/webhooks/stripe').set('stripe-signature','t=1700000000,v1=deadbeef').set('content-type','application/json').send(Buffer.from(body)).expect(401);
    expect(processEvent).not.toHaveBeenCalled();
  });
  it('REJECTS replay attack (timestamp outside tolerance)',async()=>{
    const clock=new FakeClock(1_700_000_000_000);
    const {app,processEvent}=buildApp(clock);
    const body=JSON.stringify({id:'evt_3'});
    const stale=sign(body,1_700_000_000-600); // 10 min old
    await request(app).post('/webhooks/stripe').set('stripe-signature',stale).set('content-type','application/json').send(Buffer.from(body)).expect(401);
    expect(processEvent).not.toHaveBeenCalled();
  });
  it('handles duplicate events idempotently (Stripe retries)',async()=>{
    const clock=new FakeClock(1_700_000_000_000);
    const {app,processEvent}=buildApp(clock);
    const body=JSON.stringify({id:'evt_dup',type:'charge.succeeded'});
    const sig=sign(body,1_700_000_000);
    await request(app).post('/webhooks/stripe').set('stripe-signature',sig).set('content-type','application/json').send(Buffer.from(body)).expect(200);
    const r2=await request(app).post('/webhooks/stripe').set('stripe-signature',sig).set('content-type','application/json').send(Buffer.from(body)).expect(200);
    expect(r2.body).toEqual({duplicate:true});
    expect(processEvent).toHaveBeenCalledOnce();
  });
});

// src/serializers/money.ts
import type {Money} from '../domain/money';
export function encodeMoney(m:Money):string{
  return JSON.stringify({amount:m.amount.toString(),currency:m.currency,scale:m.scale});
}
export function decodeMoney(s:string):Money{
  const o=JSON.parse(s) as {amount:string;currency:string;scale:number};
  return {amount:BigInt(o.amount),currency:o.currency,scale:o.scale};
}

// src/serializers/money.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {encodeMoney,decodeMoney} from './money';

const moneyArb=fc.record({
  amount:fc.bigInt({min:-(2n**63n),max:2n**63n-1n}),
  currency:fc.constantFrom('USD','EUR','GBP','JPY','BHD'),
  scale:fc.integer({min:0,max:8})
});

describe('Money serializer round-trip',()=>{
  it('decode(encode(x)) === x for any valid Money',()=>{
    fc.assert(fc.property(moneyArb,(m)=>{
      const r=decodeMoney(encodeMoney(m));
      return r.amount===m.amount&&r.currency===m.currency&&r.scale===m.scale;
    }),{numRuns:1000});
  });
  it('encode output is always valid JSON',()=>{
    fc.assert(fc.property(moneyArb,(m)=>{
      expect(()=>JSON.parse(encodeMoney(m))).not.toThrow();
    }),{numRuns:1000});
  });
  it('handles extreme bigints without precision loss',()=>{
    const extremes:bigint[]=[0n,1n,-1n,2n**62n,-(2n**62n),9_007_199_254_740_993n]; // MAX_SAFE_INT+2
    for(const a of extremes){
      const m={amount:a,currency:'USD',scale:8};
      const r=decodeMoney(encodeMoney(m));
      expect(r.amount).toBe(a);
    }
  });
});

// src/date/range.ts
export function isDateInRange(d:Date,start:Date,end:Date):boolean{
  return d.getTime()>=start.getTime()&&d.getTime()<=end.getTime();
}

// src/date/range.test.ts
import {describe,it,expect} from 'vitest';
import {isDateInRange} from './range';
const start=new Date('2026-01-01T00:00:00.000Z');
const end=new Date('2026-12-31T23:59:59.999Z');

describe('isDateInRange',()=>{
  // Generic happy-path
  it('returns true for a date inside the range',()=>{
    expect(isDateInRange(new Date('2026-06-15T12:00:00Z'),start,end)).toBe(true);
  });
  // BOUNDARY: kills `>= → >` mutation on start
  it('returns true at EXACTLY the start instant (boundary, inclusive)',()=>{
    expect(isDateInRange(start,start,end)).toBe(true);
  });
  // BOUNDARY: kills `>= → >` mutation in conjunction with above
  it('returns false 1ms before start',()=>{
    expect(isDateInRange(new Date(start.getTime()-1),start,end)).toBe(false);
  });
  // BOUNDARY: kills `<= → <` mutation on end
  it('returns true at EXACTLY the end instant (boundary, inclusive)',()=>{
    expect(isDateInRange(end,start,end)).toBe(true);
  });
  // BOUNDARY: kills `<= → <` mutation in conjunction with above
  it('returns false 1ms after end',()=>{
    expect(isDateInRange(new Date(end.getTime()+1),start,end)).toBe(false);
  });
  // Kills `&& → ||` mutation: a date outside one bound but inside the other should fail
  it('returns false when after end (would pass under || mutation)',()=>{
    expect(isDateInRange(new Date('2027-01-01T00:00:00Z'),start,end)).toBe(false);
  });
  it('returns false when before start (would pass under || mutation)',()=>{
    expect(isDateInRange(new Date('2025-12-31T23:59:59Z'),start,end)).toBe(false);
  });
});

